// ============================================
// MCP SERVER - ROUTER DE ACCIONES
// ============================================

const body = $input.item.json;
const action = body.action || body.tool || 'health';

// Router de acciones MCP
const actions = {
  'health': async () => ({
    success: true,
    service: 'mcp-server',
    status: 'healthy',
    timestamp: new Date().toISOString(),
    version: '1.0.0'
  }),

  'odoo_create_partner': async () => {
    // Conectar a Odoo y crear partner
    return {
      success: true,
      partner_id: Math.floor(Math.random() * 1000) + 100,
      message: 'Partner creado (simulado)'
    };
  },

  'odoo_search_partner': async () => {
    return {
      success: true,
      partners: [],
      count: 0
    };
  },

  'picoclaw_check_validated': async () => {
    return {
      success: true,
      validated: false,
      message: 'Cliente no validado'
    };
  },

  'picoclaw_build_sale': async () => {
    return {
      success: true,
      order_id: Math.floor(Math.random() * 100) + 1,
      message: 'Venta construida'
    };
  },

  'dte_generate': async () => {
    return {
      success: true,
      dte_id: 'F33E1234567',
      status: 'GENERADO'
    };
  },

  'default': async () => ({
    success: true,
    message: `Acción '${action}' recibida`,
    data: body,
    timestamp: new Date().toISOString()
  })
};

const handler = actions[action] || actions['default'];
const result = await handler();

return { json: result };
